package org.apache.commons.csv;

import static org.mockito.ArgumentMatchers.any;
import static org.mockito.Mockito.*;

import java.io.IOException;
import java.lang.reflect.Method;
import java.util.Arrays;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class CSVPrinterTest {

    private Appendable out;
    private CSVFormat format;
    private CSVPrinter printer;

    @BeforeEach
    void setUp() {
        out = mock(Appendable.class);
        format = mock(CSVFormat.class);
        printer = new CSVPrinter(out, format);
    }

    @Test
    void testPrintRecords_withObjectArrayContainingObjectArray() throws Exception {
        Object[] nested = new Object[] { "nested1", "nested2" };
        Object[] values = new Object[] { nested };
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.printRecords(values);

        // Use reflection to specify printRecord(Object... values)
        Method printRecordArray = CSVPrinter.class.getMethod("printRecord", Object[].class);
        verify(spyPrinter).printRecord((Object[]) nested);
        verify(spyPrinter).printRecord((Object[]) nested);
    }

    @Test
    void testPrintRecords_withObjectArrayContainingIterable() throws Exception {
        Iterable<String> iterable = Arrays.asList("a", "b");
        Object[] values = new Object[] { iterable };
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.printRecords(values);

        // Use reflection to specify printRecord(Iterable<?> values)
        Method printRecordIterable = CSVPrinter.class.getMethod("printRecord", Iterable.class);
        verify(spyPrinter).printRecord(iterable);
    }

    @Test
    void testPrintRecords_withObjectArrayContainingOtherObject() throws Exception {
        Object value = "stringValue";
        Object[] values = new Object[] { value };
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.printRecords(values);

        // Use reflection to specify printRecord(Object value)
        Method printRecordObject = CSVPrinter.class.getMethod("printRecord", Object[].class);
        // But printRecord(Object) is not declared in CSVPrinter, only printRecord(Object...) and printRecord(Iterable<?>)
        // So to verify printRecord(Object), we need to verify printRecord(Object) call, but it doesn't exist explicitly.
        // Actually, printRecord(Object...) is varargs, so printRecord(Object) call will call printRecord(Object...) with one argument.
        // So verify printRecord(Object...) with one argument equal to value.
        verify(spyPrinter).printRecord(value);
    }

    @Test
    void testPrintRecords_withEmptyArray() throws Exception {
        Object[] values = new Object[0];
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.printRecords(values);

        // Use reflection to get methods
        Method printRecordArray = CSVPrinter.class.getMethod("printRecord", Object[].class);
        Method printRecordIterable = CSVPrinter.class.getMethod("printRecord", Iterable.class);

        // verify printRecord(Object...) never called
        verify(spyPrinter, never()).printRecord((Object[]) any());
        // verify printRecord(Iterable<?>) never called
        verify(spyPrinter, never()).printRecord((Iterable<?>) any());
        // verify printRecord(Object) never called
        // Since printRecord(Object) does not exist explicitly, this is covered by printRecord(Object...)
    }

    @Test
    void testPrintRecords_withNullValueInArray() throws Exception {
        Object[] values = new Object[] { null };
        CSVPrinter spyPrinter = Mockito.spy(printer);

        spyPrinter.printRecords(values);

        // null is treated as Object, so printRecord(Object) called with null
        verify(spyPrinter).printRecord((Object) null);
    }
}
